import{_ as a,o as i,c as e,ak as n}from"./chunks/framework.DwHlt8HN.js";const c=JSON.parse('{"title":"Kubernetes 网络模型：Pod IP 与 Service IP","description":"","frontmatter":{},"headers":[],"relativePath":"devops/k8s/network-model.md","filePath":"devops/k8s/network-model.md","lastUpdated":1774334277000}'),l={name:"devops/k8s/network-model.md"};function p(t,s,r,d,h,o){return i(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="kubernetes-网络模型-pod-ip-与-service-ip" tabindex="-1">Kubernetes 网络模型：Pod IP 与 Service IP <a class="header-anchor" href="#kubernetes-网络模型-pod-ip-与-service-ip" aria-label="Permalink to “Kubernetes 网络模型：Pod IP 与 Service IP”">​</a></h1><p>「每个 Pod 都有独立 IP」——这是 K8s 网络模型最核心的设计，也是理解整个集群通信的起点。</p><p>你有没有想过：Pod 重启后 IP 变了，Service 怎么还能找到它？为什么 K8s 要给每个 Pod 分配一个独立的 IP，而不是像 Docker 默认的 NAT 模式那样？</p><p>这一篇，我们来搞清楚 K8s 网络模型的设计哲学。</p><h2 id="k8s-网络模型的核心原则" tabindex="-1">K8s 网络模型的核心原则 <a class="header-anchor" href="#k8s-网络模型的核心原则" aria-label="Permalink to “K8s 网络模型的核心原则”">​</a></h2><p>K8s 对网络模型做了三条强制约束，任何 CNI 插件都必须遵守：</p><h3 id="原则一-每个-pod-有独立-ip" tabindex="-1">原则一：每个 Pod 有独立 IP <a class="header-anchor" href="#原则一-每个-pod-有独立-ip" aria-label="Permalink to “原则一：每个 Pod 有独立 IP”">​</a></h3><p>集群中的每个 Pod 都拥有一个唯一的 IP 地址，不同 Pod 之间可以直接通信，无需 NAT。</p><p>这和 Docker 默认的 <code>bridge</code> 网络模式有本质区别。Docker 默认模式下，容器通过 NAT 访问外部网络，容器 IP 是对外部隐藏的。而 K8s 要求 <strong>Pod IP 在整个集群内可见且可路由</strong>。</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 在 Pod 内查看自己的 IP</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -it</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx-pod</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> addr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> show</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> eth0</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 输出类似：inet 10.244.1.15/32 scope global eth0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="原则二-节点上的-pod-可以和任意节点上的-pod-通信" tabindex="-1">原则二：节点上的 Pod 可以和任意节点上的 Pod 通信 <a class="header-anchor" href="#原则二-节点上的-pod-可以和任意节点上的-pod-通信" aria-label="Permalink to “原则二：节点上的 Pod 可以和任意节点上的 Pod 通信”">​</a></h3><p>无论 Pod 运行在哪个节点上，它们都应该能够直接通信，无需经过 NAT 转换。</p><p>这意味着整个集群形成一个扁平的三层网络（IP 层），Pod 之间是 peer-to-peer 关系。</p><h3 id="原则三-agent-可以和集群内所有-pod-通信" tabindex="-1">原则三：Agent 可以和集群内所有 Pod 通信 <a class="header-anchor" href="#原则三-agent-可以和集群内所有-pod-通信" aria-label="Permalink to “原则三：Agent 可以和集群内所有 Pod 通信”">​</a></h3><p>节点上的 kubelet、system daemons，以及 Control Plane 组件（如 kube-proxy），能够直接和集群内的任意 Pod 通信。</p><h2 id="pod-ip-的生命周期" tabindex="-1">Pod IP 的生命周期 <a class="header-anchor" href="#pod-ip-的生命周期" aria-label="Permalink to “Pod IP 的生命周期”">​</a></h2><p>Pod IP 不是永久的——它是绑定到 Pod 的生命周期上的：</p><ul><li>Pod 被删除 → IP 被回收</li><li>Pod 被调度到新节点 → IP 变化</li><li>Pod 被 HPA 扩容出来 → 新 IP</li><li>Pod 滚动更新 → 新旧 Pod 同时存在，各有各的 IP</li></ul><p>这就引出了一个问题：<strong>客户端怎么能不依赖 IP 变化？</strong> 答案是 Service。</p><h2 id="service-ip-vs-pod-ip" tabindex="-1">Service IP vs Pod IP <a class="header-anchor" href="#service-ip-vs-pod-ip" aria-label="Permalink to “Service IP vs Pod IP”">​</a></h2><p>Service 拥有的是一个 <strong>ClusterIP</strong>，这是一个虚拟 IP，不绑定在任何网卡上。它存在于 kube-proxy 维护的 iptables/IPVS 规则中。</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>┌─────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                  Kubernetes Cluster                 │</span></span>
<span class="line"><span>│                                                     │</span></span>
<span class="line"><span>│  Service (ClusterIP: 10.96.0.100)                   │</span></span>
<span class="line"><span>│    └── selector: app=nginx                          │</span></span>
<span class="line"><span>│                                                     │</span></span>
<span class="line"><span>│  ┌──────────────────┐   ┌──────────────────┐        │</span></span>
<span class="line"><span>│  │  Pod (10.244.1.15)│   │  Pod (10.244.2.8) │        │</span></span>
<span class="line"><span>│  │  nginx replica-1  │   │  nginx replica-2  │        │</span></span>
<span class="line"><span>│  └──────────────────┘   └──────────────────┘        │</span></span>
<span class="line"><span>│       Node 1                  Node 2                │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>Service 的路由规则由 kube-proxy 管理，客户端只需要知道 Service 的 ClusterIP 即可，不用关心后端 Pod 的具体 IP。</p><h2 id="两种-ip-的对比" tabindex="-1">两种 IP 的对比 <a class="header-anchor" href="#两种-ip-的对比" aria-label="Permalink to “两种 IP 的对比”">​</a></h2><table tabindex="0"><thead><tr><th>特性</th><th>Pod IP</th><th>Service ClusterIP</th></tr></thead><tbody><tr><td>本质</td><td>分配在 Pod 的网卡上</td><td>虚拟 IP，不绑定网卡</td></tr><tr><td>生命周期</td><td>跟随 Pod</td><td>跟随 Service</td></tr><tr><td>变化频率</td><td>Pod 调度/重启时变化</td><td>通常不变</td></tr><tr><td>通信方式</td><td>Pod-to-Pod 直接路由</td><td>走 kube-proxy 规则转发</td></tr><tr><td>负载均衡</td><td>无</td><td>有（iptables/IPVS）</td></tr><tr><td>可达性</td><td>集群内任意节点</td><td>集群内任意 Pod</td></tr><tr><td>Headless Service</td><td>直接返回 Pod IP 列表</td><td>无 ClusterIP</td></tr></tbody></table><h2 id="clusterip-的分配机制" tabindex="-1">ClusterIP 的分配机制 <a class="header-anchor" href="#clusterip-的分配机制" aria-label="Permalink to “ClusterIP 的分配机制”">​</a></h2><p>ClusterIP 的分配由 kube-apiserver 配合 etcd 管理。默认情况下，Service ClusterIP 从 Service Cluster IP Range（<code>--service-cluster-ip-range</code>，默认 <code>10.96.0.0/12</code>）中分配。</p><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">apiVersion</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">v1</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">kind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Service</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">metadata</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nginx-svc</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">spec</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  selector</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    app</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nginx</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  ports</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">port</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">80</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # Service 暴露的端口</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">      targetPort</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8080</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 后端 Pod 监听的端口</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  clusterIP</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">10.96.0.200</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 可选，指定固定 ClusterIP</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>你也可以声明 <code>clusterIP: None</code> 创建一个 Headless Service，此时 DNS 直接返回后端 Pod 的 IP 列表，适用于有状态应用的直接发现。</p><h2 id="网络模型的实现-cni" tabindex="-1">网络模型的实现：CNI <a class="header-anchor" href="#网络模型的实现-cni" aria-label="Permalink to “网络模型的实现：CNI”">​</a></h2><p>K8s 本身不实现网络，它只定义规则，实际的网络通信由 <strong>CNI（Container Network Interface）插件</strong> 实现。常见的 CNI 插件有：</p><ul><li><strong>Flannel</strong>：简单-overlay，VXLAN 后端</li><li><strong>Calico</strong>：高性能，支持 NetworkPolicy</li><li><strong>Cilium</strong>：基于 eBPF，深度可观测性</li><li><strong>Kube-router</strong>：轻量，集成 IPVS</li></ul><p>不同 CNI 插件实现 Pod 网络的方式不同，但它们都遵循 K8s 的三条网络原则。</p><h2 id="为什么这样设计" tabindex="-1">为什么这样设计？ <a class="header-anchor" href="#为什么这样设计" aria-label="Permalink to “为什么这样设计？”">​</a></h2><p>K8s 网络模型的设计背后有一个核心理念：<strong>网络应该是透明的</strong>。</p><p>应用开发者不需要关心网络拓扑，不需要关心 Pod 调度到哪里。Service 提供了稳定的接入点，Pod 可以自由调度，网络插件负责把「找到正确的 Pod」这件事做好。</p><p>这种设计让 K8s 天然支持：</p><ul><li><strong>Pod 的任意扩缩容</strong>：新 Pod 自动被 Service 纳入负载均衡</li><li><strong>Pod 的任意迁移</strong>：只要 Service 在，客户端无感知</li><li><strong>滚动更新</strong>：新旧 Pod 同时存在，流量自动切换</li></ul><h2 id="面试追问方向" tabindex="-1">面试追问方向 <a class="header-anchor" href="#面试追问方向" aria-label="Permalink to “面试追问方向”">​</a></h2><ul><li>Service 的 ClusterIP 是怎么工作的？kube-proxy 用的是什么机制？</li><li>跨节点的 Pod 通信，数据包是怎么路由的？</li><li>Pod 和 Service 的 DNS 记录分别是什么格式？</li></ul><blockquote><p>K8s 网络模型的本质是「扁平 + 可路由」。理解了这一点，你就理解了集群内所有通信的底层逻辑。</p></blockquote>`,41)])])}const b=a(l,[["render",p]]);export{c as __pageData,b as default};
